const data = $input.first().json;
const failures = data.failures || [];
const results = data.results || {};

const PROVIDER_URLS = {
  GROQ_API_KEY:         'https://console.groq.com/keys',
  DEEPSEEK_API_KEY:     'https://platform.deepseek.com/api_keys',
  PERPLEXITY_API_KEY:   'https://www.perplexity.ai/settings/api',
  XAI_API_KEY:          'https://console.x.ai/',
  ANTHROPIC_API_KEY:    'https://console.anthropic.com/settings/keys',
  OPENAI_API_KEY:       'https://platform.openai.com/api-keys',
  GEMINI_API_KEY:       'https://aistudio.google.com/app/apikey',
  CLOUDFLARE_API_TOKEN: 'https://dash.cloudflare.com/profile/api-tokens',
  GREPTILE_API_KEY:     'https://app.greptile.com/settings/api',
};

let lines = ['🔴 *API Key Failures Detected*\n'];
for (const k of failures) {
  const r = results[k] || {};
  const present = r.present ? '(key present but invalid)' : '(key missing)';
  const code = r.status_code ? ` [HTTP ${r.status_code}]` : '';
  const url = PROVIDER_URLS[k] || 'N/A';
  lines.push(`• *${k}*${code} ${present}`);
  lines.push(`  Renew at: ${url}`);
}

lines.push('\nUse POST /webhook/rotate-api-key with {\"key_name\": \"...\", \"key_value\": \"...\"}  to update');

return [{ json: { message: lines.join('\n'), failures } }];

